fix_1_selective_attention.implementation:
In gc.go NewGcHandler, add before the default case:

case EventTransportMessage:
    // Selective attention: filter messages not addressed to us
    to := evt.Payload["to_agent"]
    if to != "" && to != cfg.AgentID && to != "all" && to != "all-agents" {
        cfg.Logger.Debug("Gc: message not addressed to us — filtered", "to", to, "agent", cfg.AgentID)
        return true
    }
    return false  // Addressed to us — needs deliberation

